from collections import deque

def solve() -> None:
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    n = int(next(it))
    h = [0] * (n + 1)          # 1‑based
    for i in range(1, n + 1):
        h[i] = int(next(it))

    # auxiliary arrays
    L = [0] * (n + 1)          # h[i] - i
    R = [0] * (n + 1)          # h[i] + i
    max_h = 0
    for i in range(1, n + 1):
        L[i] = h[i] - i
        R[i] = h[i] + i
        if h[i] > max_h:
            max_h = h[i]

    # upper bound for t
    upper = min(max_h, (n - 1) // 2)

    INF = 10 ** 20

    # ---------- check(t) ----------
    def check(t: int) -> bool:
        if t == 0:
            # at least one block exists initially (h_i >= 1)
            return True
        if t > (n - 1) // 2:
            return False
        w = t + 1                     # window size

        # left minima: min L on [i-w+1 .. i]
        left_min = [INF] * (n + 1)
        dq = deque()
        for i in range(1, n + 1):
            # push i
            while dq and L[dq[-1]] >= L[i]:
                dq.pop()
            dq.append(i)
            # remove out of window
            while dq and dq[0] < i - w + 1:
                dq.popleft()
            if i >= w:
                left_min[i] = L[dq[0]]

        # right minima: min R on [i .. i+w-1]
        right_min = [INF] * (n + 1)
        dq.clear()
        for i in range(n, 0, -1):
            while dq and R[dq[-1]] >= R[i]:
                dq.pop()
            dq.append(i)
            while dq and dq[0] > i + w - 1:
                dq.popleft()
            if i + w - 1 <= n:
                right_min[i] = R[dq[0]]

        # test all possible centres
        for i in range(t + 1, n - t + 1):
            if left_min[i] >= (t + 1 - i) and right_min[i] >= (t + 1 + i):
                return True
        return False

    # ---------- binary search ----------
    lo = 0
    hi = upper + 1          # exclusive, invariant: check(lo) true, check(hi) false
    while lo + 1 < hi:
        mid = (lo + hi) // 2
        if check(mid):
            lo = mid
        else:
            hi = mid

    # answer = lo + 1
    print(lo + 1)


